/**
 * ============================================================
 * ABNAN CRM — Frontend API Service v2 (FIXED)
 * ============================================================
 */

import axios from 'axios';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

// ── Axios Instances ───────────────────────────────────────────
export const api = axios.create({
  baseURL: API_URL,
  withCredentials: true,
  timeout: 30000,
  headers: { 'Content-Type': 'application/json' },
});

export const publicApi = axios.create({
  baseURL: API_URL,
  withCredentials: true,
  timeout: 30000,
});

// ── Request Deduplication ─────────────────────────────────────
const pendingRequests = new Map();

function dedupeKey(config) {
  if (config.method?.toLowerCase() !== 'get') return null;
  return `${config.method}:${config.url}:${JSON.stringify(config.params || {})}`;
}

// ── INTERCEPTOR REQUEST: Tambahkan Token ──────────────────────
api.interceptors.request.use(
  (config) => {
    // Ambil token dari localStorage
    const token = localStorage.getItem('abnan_token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    } else {
      // Hapus header Authorization jika tidak ada token
      delete config.headers.Authorization;
    }

    // Deduplication untuk GET
    const key = dedupeKey(config);
    if (key) {
      if (pendingRequests.has(key)) {
        const controller = new AbortController();
        controller.abort();
        config.signal = controller.signal;
      } else {
        const controller = new AbortController();
        config.signal = controller.signal;
        config._dedupeKey = key;
        pendingRequests.set(key, controller);
      }
    }

    // [DEBUG] Bisa dihapus setelah masalah selesai
    console.log(`[API] ${config.method?.toUpperCase()} ${config.url} - Token: ${token ? 'Ada' : 'Tidak ada'}`);
    return config;
  },
  (error) => Promise.reject(error)
);

// ── INTERCEPTOR RESPONSE: Handle 401 & Bersihkan Duplikasi ────
api.interceptors.response.use(
  (response) => {
    const key = response.config._dedupeKey;
    if (key) pendingRequests.delete(key);
    return response;
  },
  (error) => {
    const key = error.config?._dedupeKey;
    if (key) pendingRequests.delete(key);

    // Jika 401 Unauthorized, hapus token dan redirect ke login
    if (error.response?.status === 401) {
      localStorage.removeItem('abnan_token');
      localStorage.removeItem('abnan_user');
      // Hindari infinite redirect jika sudah di halaman login
      if (!window.location.pathname.includes('/login')) {
        window.location.replace('/login');
      }
    }

    const message =
      error.response?.data?.message ||
      (error.code === 'ECONNABORTED'
        ? 'Request timeout. Coba lagi.'
        : error.code === 'ERR_NETWORK'
        ? 'Tidak dapat terhubung ke server.'
        : error.message || 'Terjadi kesalahan jaringan');

    error.userMessage = message;
    return Promise.reject(error);
  }
);

// ── Retry Helper ──────────────────────────────────────────────
async function withRetry(fn, retries = 2, delay = 500) {
  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      return await fn();
    } catch (err) {
      const isNetworkErr = !err.response && err.code !== 'ERR_CANCELED';
      if (attempt < retries && isNetworkErr) {
        await new Promise((r) => setTimeout(r, delay * Math.pow(2, attempt)));
      } else {
        throw err;
      }
    }
  }
}

// ── API Modules ───────────────────────────────────────────────
export const authAPI = {
  login: (data) => api.post('/auth/login', data),
  me: () => api.get('/auth/me'),
  changePassword: (data) => api.post('/auth/change-password', data),
};

export const customerPortalAPI = {
  getOverview: () => api.get('/customer-portal/overview'),
};

export const customerSetupAPI = {
  getSetupInfo: (token) => publicApi.get(`/customer-portal/setup/${token}`),
  completeSetup: (token, data) => publicApi.post(`/customer-portal/setup/${token}`, data),
};

export const portalAccessAPI = {
  getByCustomerId: (cid) => api.get(`/customer-portal-admin/customers/${cid}/access`),
  upsert: (cid, data) => api.put(`/customer-portal-admin/customers/${cid}/access`, data),
  createSetupLink: (cid, data) => api.post(`/customer-portal-admin/customers/${cid}/setup-link`, data),
};

export const usersAPI = {
  getAll: (params) => withRetry(() => api.get('/users', { params })),
  getById: (id) => api.get(`/users/${id}`),
  create: (data) => api.post('/users', data),
  update: (id, d) => api.put(`/users/${id}`, d),
  delete: (id) => api.delete(`/users/${id}`),
  profile: () => api.get('/users/me/profile'),
  updateProfile: (data) => api.put('/users/me/profile', data),
};

